import csv
from models import BugTask, FeatureTask

def load_tasks(path):
    tasks = []
    with open(path, newline="") as file:
        for row in csv.DictReader(file):
            completed = row["completed"].lower() == "true"
            if row["kind"] == "bug":
                task = BugTask(row["title"], row["priority"], row["detail"], completed)
            elif row["kind"] == "feature":
                task = FeatureTask(row["title"], row["priority"], int(row["detail"]), completed)
            else:
                raise ValueError(f"unknown task kind: {row['kind']}")
            tasks.append(task)
    return tasks

